import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface LatestReading {
  systolic: number;
  diastolic: number;
  category: string;
}

interface TrendData {
  systolic: number[];
  diastolic: number[];
}

interface BloodPressureData {
  latestReading: LatestReading;
  trendData: TrendData;
}

export default function Widget() {
  const data = response.data as BloodPressureData;
  const { latestReading, trendData } = data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 0.5 }}>
              Latest Reading
            </Typography>
            <Typography variant="h4" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
              {latestReading.systolic}/{latestReading.diastolic} mmHg
            </Typography>
            <Typography variant="body2" sx={{ color: '#10B981' }}>
              {latestReading.category}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: trendData.systolic,
                  color: '#FF6F61',
                  label: 'Systolic',
                  curve: 'linear',
                },
                {
                  type: 'line',
                  data: trendData.diastolic,
                  color: '#FFD700',
                  label: 'Diastolic',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'linear',
                  data: trendData.systolic.map((_, index) => index),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'pressure' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="pressure"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
